#include<cstdio>
#include<iostream>
using namespace std;
int n, m, t, sx, sy, fx, fy, ans;
bool vis[10][10];
bool mp[10][10];
int Xx[] = {1, 0, -1, 0};
int Yy[] = {0, -1, 0, 1};
void dfs(int x, int y) {
	if (x == fx && y == fy) {
		ans++;
		return;
	}
	for (int i = 0; i < 4; i++) {
		int dx = Xx[i] + x;
		int dy = Yy[i] + y;
		if (dx >= 1 && dx <= n && dy >= 1 && dy <= m && !vis[dx][dy] && !mp[dx][dy]) {
			vis[x][y] = 1;
			dfs(dx, dy);
			vis[x][y] = 0;
		}
	}
}
int main() {
	cin >> n >> m >> t;
	cin >> sx >> sy >> fx >> fy;
	while (t--) {
		int x, y;
		cin >> x >> y;
		mp[x][y] = 1;
	}
	dfs(sx, sy);
	cout << ans;
	return 0;
}
